def missingNumber(nums):
    n=len(nums)
    return n*(n+1)//2-sum(nums)

def moveZeroes(nums):
    i=0
    for j in range(len(nums)):
        if nums[j]!=0:
            nums[i],nums[j]=nums[j],nums[i]
            i+=1

def wordPattern(pattern,s):
    words=s.split()
    if len(pattern)!=len(words):
        return False
    char_to_word={}
    word_to_char={}
    for c,w in zip(pattern,words):
        if c in char_to_word:
            if char_to_word[c]!=w:
                return False
        else:
            if w in word_to_char:
                return False
            char_to_word[c]=w
            word_to_char[w]=c
    return True

def addDigits(num):
    while num>=10:
        num=sum(map(int,str(num)))
    return num

def search(nums,target):
    left,right=0,len(nums)-1
    while left<=right:
        mid=(left+right)//2
        if nums[mid]==target:
            return mid
        elif nums[mid]<target:
            left=mid+1
        else:
            right=mid-1
    return -1

def firstBadVersion(n):
    left,right=1,n
    while left<right:
        mid=(left+right)//2
        if isBadVersion(mid):
            right=mid
        else:
            left=mid+1
    return left

def canConstruct(ransomNote,magazine):
    from collections import Counter
    return not Counter(ransomNote)-Counter(magazine)

def fizzBuzz(n):
    result=[]
    for i in range(1,n+1):
        if i%15==0:
            result.append('FizzBuzz')
        elif i%3==0:
            result.append('Fizz')
        elif i%5==0:
            result.append('Buzz')
        else:
            result.append(str(i))
    return result

def isPalindrome(s):
    s=''.join(c.lower() for c in s if c.isalnum())
    return s==s[::-1]

def isHappy(n):
    def get_next(num):
        return sum(int(digit)**2 for digit in str(num))
    seen=set()
    while n!=1 and n not in seen:
        seen.add(n)
        n=get_next(n)
    return n==1

class ListNode:
    def __init__(self,val=0,next=None):
        self.val=val
        self.next=next

def reverseList(head):
    prev=None
    curr=head
    while curr:
        next_node=curr.next
        curr.next=prev
        prev=curr
        curr=next_node
    return prev

class MyQueue:
    def __init__(self):
        self.stack1=[]
        self.stack2=[]
    def push(self,x):
        self.stack1.append(x)
    def pop(self):
        if not self.stack2:
            while self.stack1:
                self.stack2.append(self.stack1.pop())
        return self.stack2.pop()
    def peek(self):
        if not self.stack2:
            while self.stack1:
                self.stack2.append(self.stack1.pop())
        return self.stack2[-1]
    def empty(self):
        return not self.stack1 and not self.stack2

def isPowerOfThree(n):
    if n<1:
        return False
    while n%3==0:
        n//=3
    return n==1

def countPrimes(n):
    if n<2:
        return 0
    sieve=[True]*n
    sieve[0]=sieve[1]=False
    for i in range(2,int(n**0.5)+1):
        if sieve[i]:
            sieve[i*i:n:i]=[False]*len(sieve[i*i:n:i])
    return sum(sieve)

def isPerfectSquare(num):
    if num<2:
        return True
    left,right=2,num//2
    while left<=right:
        mid=(left+right)//2
        if mid*mid==num:
            return True
        elif mid*mid<num:
            left=mid+1
        else:
            right=mid-1
    return False

def firstUniqChar(s):
    from collections import Counter
    count=Counter(s)
    for i,char in enumerate(s):
        if count[char]==1:
            return i
    return -1

def findTheDifference(s,t):
    from collections import Counter
    return list((Counter(t)-Counter(s)).keys())[0]

def longestPalindrome(s):
    from collections import Counter
    count=Counter(s)
    length=0
    odd_found=False
    for char,freq in count.items():
        if freq%2==0:
            length+=freq
        else:
            length+=freq-1
            odd_found=True
    return length+1 if odd_found else length

def singleNumber(nums):
    result=0
    for num in nums:
        result^=num
    return result
